"""
MKT Christ — 2 Samuel chapters 19–21
Run: python3 scripts/zc-christ-2samuel-19-21-full.py

Ch19: David's return after Absalom's defeat; Shimei pardoned; Mephibosheth; Barzillai (43 verses)
Ch20: Sheba's rebellion; Amasa murdered by Joab; wise woman of Abel; cabinet list (26 verses)
Ch21: Gibeonite reparations; Rizpah's vigil; David rescued; the four Philistine giants (22 verses)

Key Christological themes:
- David weeping for Absalom (19:1-4) → Christ weeping for those who rebel against him
- The people debating the king's return (19:9-10) → the human debate about receiving Christ
- Shimei's pardon by the returning king → Christ forgiving from the cross (Luke 23:34)
- Mephibosheth's restored covenant inheritance → the disabled who depend wholly on covenant grace
- Barzillai/Chimham: faithful service and generational covenant succession
- Sheba's rebellion as type of the final anti-christ uprising (Rev 20:7-9)
- The wise woman of Abel: wisdom preserving the city by surrendering the rebel (1 Cor 1:30)
- The seven hanged sons of Saul → substitutionary atonement for covenant violation
- Mephibosheth spared by covenant oath (21:7) → those sheltered by Christ's covenant
- Rizpah's vigil over the crucified → the women at the cross and tomb (Luke 23:49)
- David nearly killed; "do not extinguish the lamp of Israel" (21:17) → Christ as the light of the world
- The four giants defeated by David's servants → the church completing Christ's victory (Col 1:24)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "19": {
    "1": "<p>Joab is told the king is weeping and mourning for Absalom. The anointed king&#8217;s grief over his rebel son is one of the most theologically charged scenes in Samuel. Christ&#8217;s lament over Jerusalem — &#8220;O Jerusalem, Jerusalem, you who kill the prophets and stone those sent to you, how often I have longed to gather your children together&#8221; (Matt 23:37) — is the NT counterpart. The king who grieves for those who rebelled against him, whose victory over the rebellion is experienced not as triumph but as loss, is the type of Christ&#8217;s heart toward those who reject him. The anointed does not rejoice at the rebel&#8217;s destruction.</p>",
    "2": "<p>The victory turned to mourning for all the people — they heard the king grieving for Absalom. The paradox of the anointed&#8217;s grief at his own victory is the paradox of the cross: the triumph of redemption is simultaneously the deepest grief of the anointed. &#8220;He was despised and rejected by men, a man of sorrows and acquainted with grief&#8221; (Isa 53:3) — the victory of the Servant is accomplished through, not despite, his grief. The people&#8217;s victory-mourning at David&#8217;s grief is the type of the disciples&#8217; confusion at the cross: the triumph they expected was not the triumph they received.</p>",
    "3": "<p>The people crept back into the city like soldiers ashamed after defeat. The reversal of the normal post-victory celebration — returning like the defeated rather than the victors — is the type of the disciples after the crucifixion: &#8220;we had hoped that he was the one to redeem Israel&#8221; (Luke 24:21), walking away from Jerusalem in dejection. The community of the anointed experiencing victory as loss, triumph as shame, reflects the pattern of the cross where the greatest victory in history was initially experienced as total defeat.</p>",
    "4": "<p>&#8220;O my son Absalom! O Absalom, my son, my son!&#8221; — the sevenfold repetition of grief. The anointed king&#8217;s lament for his rebellious son is the type of YHWH&#8217;s grief over Israel&#8217;s rebellion: &#8220;How can I give you up, O Ephraim? How can I hand you over, O Israel?&#8221; (Hos 11:8). Christ&#8217;s weeping over Jerusalem (Luke 19:41) is the supreme fulfillment of the anointed&#8217;s grief for the rebel people. The cry &#8220;my son, my son&#8221; anticipates the anguish of the Father as the Son bears the weight of the rebels&#8217; sin — &#8220;My God, my God, why have you forsaken me?&#8221; (Matt 27:46) — the deepest cry of the anointed in history.</p>",
    "5": "<p>Joab rebukes David: &#8220;You have shamed all your servants who today saved your life.&#8221; The rebuke of the anointed by his closest military commander is a type of every human attempt to redirect the anointed&#8217;s grief toward self-interest. Peter&#8217;s rebuke of Jesus — &#8220;Far be it from you, Lord! This shall never happen to you&#8221; (Matt 16:22) — has the same structure: the lieutenant who cannot understand why the anointed would grieve rather than triumph. Joab&#8217;s pragmatic calculation (stop mourning, reward your troops, or you&#8217;ll lose everything) is the worldly wisdom that misreads the anointed&#8217;s heart.</p>",
    "6": "<p>&#8220;You love those who hate you and hate those who love you.&#8221; Joab&#8217;s accusation is, from the perspective of covenant love, actually a description of Christ&#8217;s own ministry: &#8220;God demonstrates his own love for us in this: while we were still sinners, Christ died for us&#8221; (Rom 5:8). The anointed who loves those who hate him and extends grief over those who rebelled against him is doing exactly what Joab considers incomprehensible. The accusation that Christ &#8220;loves sinners&#8221; — made by the Pharisees (Luke 15:2) — is the Joab-rebuke applied to Christ. It is meant as an accusation; it is actually the gospel.</p>",
    "7": "<p>Joab&#8217;s ultimatum: go out and speak to your servants or I swear they will desert you. The political calculation — that the anointed must perform strength or lose his following — is the logic of worldly kingship that Christ consistently refuses. At Gethsemane, Jesus could have called twelve legions of angels (Matt 26:53); he chose the cross instead of performance. The anointed&#8217;s willingness to appear weak, to grieve publicly, to refuse the expected victory-display, is precisely what the Joab-mentality cannot accept. Christ never performed strength to retain his followers; he consistently called them to follow him into apparent weakness.</p>",
    "8": "<p>David gets up and sits in the gate — the public resumption of royal function despite personal grief. The anointed returning to his public role after private anguish is the type of Christ&#8217;s resurrection appearance: after the grief of the cross and the darkness of the tomb, the risen king appears publicly to his disciples, resuming his shepherding role (John 20:19-20; 21:15-17). The gate — the legal and public center of the city — is where the anointed is needed; David goes there not because the grief is resolved but because the people need their king.</p>",
    "9": "<p>All the people throughout the tribes were arguing: &#8220;The king rescued us from the hand of our enemies, and delivered us from the Philistines.&#8221; The people debating whether to bring back the anointed king is the type of the human debate about receiving Christ. The argument recognizes his saving acts — &#8220;he rescued us&#8221; — before the community commits to receiving him. This is the pattern of Acts 2: Peter&#8217;s sermon recounts what God did through Jesus (2:22-36) before the crowd asks &#8220;what shall we do?&#8221; (2:37). The recognition of saving acts precedes the decision to receive the savior-king.</p>",
    "10": "<p>&#8220;But Absalom, whom we anointed over us, is dead in battle. Why are you saying nothing about bringing the king back?&#8221; The collapse of the false king clears the way for the return of the true king. The death of the rival anointed — the one the people themselves had elevated — is what opens the question of the true king&#8217;s return. Paul&#8217;s argument in Rom 10:9: &#8220;if you confess with your mouth that Jesus is Lord and believe in your heart that God raised him from the dead, you will be saved&#8221; — the resurrection of the true anointed and the collapse of all rival claims is the basis for receiving him. The rebel king&#8217;s death opens the throne for the rightful king.</p>",
    "11": "<p>David sends to Zadok and Abiathar for the elders of Judah: &#8220;Why should you be the last to bring the king back?&#8221; The anointed appealing first to his own tribe — Judah — to receive him back is the type of the gospel&#8217;s priority to Israel. Paul in Rom 11:11-15 grieves that Israel has not received its own king; Christ himself went first to the lost sheep of the house of Israel (Matt 15:24). The appeal to Judah to take the lead in receiving the returning king is the type of the apostolic appeal to the Jewish community to be the first to confess the risen Christ.</p>",
    "12": "<p>&#8220;You are my kinsmen, my own bone and flesh. Why should you be the last to bring the king back?&#8221; The appeal to kinship — the same language as the covenant formula of marriage and political union (Gen 2:23; 2 Sam 5:1) — is the anointed invoking the deepest covenant bond. Christ&#8217;s appeal to his own people through the apostles is the same kinship-claim: &#8220;salvation is from the Jews&#8221; (John 4:22); &#8220;to his own he came, and his own people did not receive him&#8221; (John 1:11). The anointed&#8217;s &#8220;you are my flesh and bone&#8221; to Judah is the type of the incarnational claim: Christ&#8217;s solidarity with his people as their kinsman-redeemer.</p>",
    "13": "<p>The appointment of Amasa as Joab&#8217;s replacement — &#8220;are you not my flesh and blood?&#8221; — is the anointed king extending reconciliation to a former rebel (Amasa commanded Absalom&#8217;s forces). The welcoming of the enemy commander into the anointed&#8217;s service is the type of Christ receiving former persecutors: Paul, who &#8220;was breathing threats and murder against the disciples of the Lord&#8221; (Acts 9:1), becomes the apostle to the Gentiles. The anointed&#8217;s appointment of former enemies to positions of service is the radical grace that Joab (who will murder Amasa) cannot comprehend.</p>",
    "14": "<p>He won over the hearts of all the men of Judah as one man — they sent word: &#8220;Return, you and all your servants.&#8221; The unified welcome of the returning king by those who had wavered is the type of the eschatological welcome of Christ: &#8220;every knee shall bow&#8221; (Phil 2:10). The &#8220;as one man&#8221; unity of the welcoming community anticipates the unity of the church as Christ&#8217;s body: &#8220;there is one body and one Spirit... one Lord, one faith, one baptism&#8221; (Eph 4:4-5). The divided, arguing people becoming unified around the returning king is the ecclesiological miracle that only the anointed&#8217;s return can accomplish.</p>",
    "15": "<p>The king returned and reached the Jordan — the climactic crossing. The Jordan as the boundary between exile and the promised land is the type of the resurrection-boundary: David returning from Transjordanian exile to the kingdom is the type of Christ ascending from death (the wilderness-beyond-Jordan) to reign. The Jordan crossings in Scripture (Joshua, Elijah, Elisha, John the Baptist) all mark decisive transitions; David&#8217;s return crossing is the political type of Christ&#8217;s return to reign after his death and resurrection.</p>",
    "16": "<p>Shimei son of Gera hurries down to meet the returning king — the man who cursed the fleeing David now prostrating before the victorious David. The reversal of Shimei&#8217;s posture — from curser to supplicant — is the type of every enemy who comes to seek mercy from the anointed they previously opposed. &#8220;Every knee will bow&#8221; (Phil 2:10) includes those who cursed and mocked Christ; the eschatological kneeling before the anointed encompasses all former enemies. Shimei&#8217;s rush to be first — &#8220;first of all the house of Joseph&#8221; (v. 20) — reflects the urgency of those who know they need pardon most urgently.</p>",
    "17": "<p>A thousand Benjaminites with Shimei, and Ziba with his fifteen sons and twenty servants. The large entourage accompanying the penitent Shimei is the type of the communal repentance that the anointed&#8217;s return enables. Individual repentance (Shimei) generates communal response (a thousand men). Pentecost is the NT instance: Peter&#8217;s proclamation of the returning/risen king produces three thousand converts in a single day (Acts 2:41). The return of the anointed creates a movement of recognition and response that goes far beyond the initial penitent.</p>",
    "18": "<p>They crossed at the ford to bring over the king&#8217;s household and to serve him. Shimei fell down before the king — the former curser now serving the one he had abused. The service rendered at the Jordan crossing — helping the king&#8217;s household over, serving as he wished — is the type of the service of those who come to Christ in repentance: &#8220;if anyone serves me, he must follow me&#8221; (John 12:26). Shimei&#8217;s crossing from curse to service is the pattern of every conversion: former opposition transformed into active service of the anointed.</p>",
    "19": "<p>&#8220;May my lord not hold me guilty; do not remember the wrong your servant did on the day my lord the king left Jerusalem.&#8221; Shimei&#8217;s petition for pardon is the type of every penitential prayer before the returning king. The appeal to the king&#8217;s mercy — not to hold guilt, not to remember the wrong — is the prayer of every sinner before Christ: &#8220;God, be merciful to me, a sinner&#8221; (Luke 18:13). The specificity of Shimei&#8217;s confession — &#8220;the wrong I did on that day&#8221; — is the type of honest, specific repentance rather than vague regret. The returning king hears the specific confession.</p>",
    "20": "<p>&#8220;Your servant knows he sinned.&#8221; The explicit acknowledgment of sin — &#8220;yāḏaʿ ʿāḇdĕḵā kî ʾănî ḥāṭāʾtî&#8221; — is the covenantal admission formula that opens the way to pardon. 1 John 1:9: &#8220;if we confess our sins, he is faithful and just to forgive us our sins and to cleanse us from all unrighteousness.&#8221; The self-identification as &#8220;first of all the house of Joseph to come down to meet the king&#8221; reflects Shimei&#8217;s eagerness to be among the earliest to seek pardon — as the thief on the cross is the first to confess Christ as king and receive the promise of paradise (Luke 23:42-43).</p>",
    "21": "<p>Abishai demands Shimei&#8217;s death: &#8220;Should he not be put to death because he cursed the LORD&#8217;s anointed?&#8221; The demand for justice against the penitent by the anointed&#8217;s own servants is the type of the disciples&#8217; indignation when mercy seems to be given too freely. The disciples rebuking those who brought children to Jesus (Mark 10:13-14), James and John asking to call down fire on the Samaritans (Luke 9:54) — the Abishai-spirit within the community of the anointed. Jesus&#8217;s rebuke: &#8220;You do not know what kind of spirit you are of&#8221; (Luke 9:55).</p>",
    "22": "<p>&#8220;What is this between you and me, sons of Zeruiah? Why should you be my adversary today?&#8221; The returning king refusing to execute justice on the day of his return is the type of Christ&#8217;s first coming as savior rather than judge: &#8220;God did not send his Son into the world to condemn the world, but to save the world through him&#8221; (John 3:17). &#8220;Should anyone die in Israel today? Do I not know that today I am king over Israel?&#8221; — the day of the king&#8217;s return is the day of mercy, not the day of judgment. This is the &#8220;acceptable year of the Lord&#8221; that Christ proclaims (Luke 4:19), the day when mercy precedes judgment.</p>",
    "23": "<p>&#8220;You shall not die.&#8221; The king&#8217;s oath of life to the penitent cursing enemy is the supreme act of covenant grace. The anointed&#8217;s sworn word of life — &#8220;lōʾ tāmûṯ&#8221; — is the type of Christ&#8217;s declarations of salvation: &#8220;truly, truly, I say to you, whoever hears my word and believes him who sent me has eternal life. He does not come into judgment, but has passed from death to life&#8221; (John 5:24). The king&#8217;s oath cannot be revoked; Christ&#8217;s word of life is irrevocable. Shimei&#8217;s pardon by oath is sealed; the believer&#8217;s salvation by Christ&#8217;s word is sealed with the Holy Spirit (Eph 1:13-14).</p>",
    "24": "<p>Mephibosheth came down to meet the king — he had not cared for his feet, trimmed his beard, or washed his clothes since the day the king left until the day he came back safely. Mephibosheth&#8217;s sustained mourning for the entire duration of the king&#8217;s absence is the type of the church&#8217;s mourning for the absent king: &#8220;we who are in this tent groan, being burdened — not that we would be unclothed, but that we would be further clothed&#8221; (2 Cor 5:4). The unwashed clothes, untrimmed beard, uncared-for feet are the outward signs of a life oriented entirely toward the king&#8217;s return. The church&#8217;s &#8220;maranatha&#8221; (&#8220;come, Lord Jesus&#8221;, Rev 22:20) is Mephibosheth&#8217;s unkempt waiting, extended across the age of the church.</p>",
    "25": "<p>&#8220;Why did you not come with me, Mephibosheth?&#8221; The king&#8217;s question is not accusatory but restorative — he is giving Mephibosheth the opportunity to explain and be fully received back. Christ&#8217;s questioning of Peter after the resurrection — &#8220;do you love me?&#8221; three times (John 21:15-17) — has the same structure: not a gotcha but a restoration. The returning king invites an account not to condemn but to clear the air between himself and the one who loves him. Mephibosheth&#8217;s answer will vindicate his loyalty; Peter&#8217;s answer will restore his call. The anointed asks so that the covenant person can speak their love clearly.</p>",
    "26": "<p>Mephibosheth&#8217;s explanation: Ziba deceived him. The lame man who could not saddle his own donkey, who depended entirely on another&#8217;s assistance to come to the king, was betrayed by that very servant. The type of those who depend on others to bring them to Christ — and whose access is controlled and potentially blocked by intermediaries — is the type that the Reformation&#8217;s doctrine of direct access to God addresses: Christ is the one mediator (1 Tim 2:5) through whom all come directly, not filtered through potentially corrupt human intermediaries. Mephibosheth&#8217;s disability that required intermediation is the type of human spiritual disability; Christ&#8217;s direct approach is the answer.</p>",
    "27": "<p>&#8220;My lord the king is like an angel of God — do whatever seems good to you.&#8221; Mephibosheth&#8217;s submission to the king&#8217;s judgment — placing his entire fate in the hands of the anointed — is the type of complete trust in Christ&#8217;s wisdom and justice. &#8220;We know that for those who love God all things work together for good&#8221; (Rom 8:28) — the believer who says to Christ &#8220;do whatever seems good to you&#8221; entrusts all circumstances to the one whose judgments are always right. Mephibosheth&#8217;s absolute trust in David&#8217;s justice — even after being wronged by Ziba — is the model of faith that does not demand its own account but trusts the anointed to see truly.</p>",
    "28": "<p>&#8220;All my father&#8217;s household deserved only death from my lord the king, yet you set your servant among those who eat at your table.&#8221; Mephibosheth&#8217;s self-description — deserving death, yet given table-fellowship — is the exact structure of the gospel: &#8220;while we were enemies we were reconciled to God through the death of his Son&#8221; (Rom 5:10). The language of &#8220;your servant&#8221;, the acknowledgment of deserved death, the wonder at table-inclusion — this is the Christian&#8217;s own testimony. The table of the anointed at which the one who deserved nothing is seated is the type of the Eucharist: the &#8220;table prepared before me in the presence of my enemies&#8221; (Ps 23:5) at which the redeemed are seated by covenant grace alone.</p>",
    "29": "<p>&#8220;Why go on talking about this? I have decided: you and Ziba divide the land.&#8221; The king&#8217;s decision — not perfectly just by earthly standards — reflects the anointed&#8217;s prerogative to adjudicate as he sees fit. Mephibosheth&#8217;s acceptance of the imperfect judgment is the type of the believer who trusts Christ&#8217;s sovereignty even when outcomes are not what they expected. The kingdom&#8217;s distribution will not always conform to human calculations of desert; the anointed&#8217;s decisions stand even when they puzzle those affected. &#8220;Is it not lawful for me to do what I choose with what belongs to me?&#8221; (Matt 20:15).</p>",
    "30": "<p>&#8220;Let him have it all, since my lord the king has returned home safely.&#8221; Mephibosheth&#8217;s relinquishment of all earthly claim in the joy of the king&#8217;s return is the type of Paul&#8217;s assessment of all earthly goods in light of Christ: &#8220;I count everything as loss because of the surpassing worth of knowing Christ Jesus my Lord&#8221; (Phil 3:8). The restored covenant relationship with the anointed is worth more than every material claim. The kingdom&#8217;s arrival renders the calculation of earthly goods irrelevant — &#8220;what does it profit a man to gain the whole world and forfeit his soul?&#8221; (Mark 8:36). Mephibosheth gains the king&#8217;s return and counts it worth everything.</p>",
    "31": "<p>Barzillai the Gileadite had provided for the king during the exile at Mahanaim. The Gileadite who sustained the anointed during his time of need is the type of those who serve Christ in his &#8220;absence&#8221; — the period of the church age. Matt 25:35-40: &#8220;I was hungry and you gave me food, I was a stranger and you welcomed me&#8221; — &#8220;whatever you did for one of the least of these brothers and sisters of mine, you did for me.&#8221; Barzillai&#8217;s provision for David in exile is the type of the care given to Christ&#8217;s people during the age when the king is not visibly present. The returning king will honor those who served him in his absence.</p>",
    "32": "<p>Barzillai was eighty years old — very old. He had provided for the king at his own expense. The faithful old man whose entire earthly provision went toward sustaining the anointed is the type of those who give extravagantly for the king&#8217;s mission. Mary&#8217;s anointing of Jesus with expensive perfume (John 12:3) receives the same honor: &#8220;wherever this gospel is proclaimed in the whole world, what she has done will also be told in memory of her&#8221; (Matt 26:13). Those who impoverish themselves for the anointed&#8217;s cause are honored by the returning king, not repaid in kind but honored in covenantal acknowledgment.</p>",
    "33": "<p>&#8220;Cross over with me and I will provide for you in Jerusalem.&#8221; The king&#8217;s invitation to Barzillai to come under his direct provision in the capital is the type of Christ&#8217;s invitation to those who have served him: &#8220;come, you who are blessed by my Father, inherit the kingdom prepared for you from the foundation of the world&#8221; (Matt 25:34). The faithful servant invited to cross over and live at the king&#8217;s expense is the eschatological inheritance: those who served the anointed in his absence are brought into his direct provision in the new Jerusalem.</p>",
    "34": "<p>Barzillai&#8217;s response: &#8220;How many years do I have left? I am too old to enjoy the king&#8217;s bounty at Jerusalem.&#8221; The old man who has served faithfully but is too near the end to enjoy the full inheritance on this side of death is the type of those who die in faith without receiving the full promise: &#8220;these all died in faith, not having received the things promised, but having seen them and greeted them from afar&#8221; (Heb 11:13). Barzillai&#8217;s age prevents his enjoyment of the Jerusalem inheritance on earth; the resurrection is the answer to every Barzillai who served the king faithfully but died before the full kingdom came.</p>",
    "35": "<p>Barzillai&#8217;s diminished capacity in old age: he can no longer hear the singing, nor taste what he eats or drinks. The physical diminishment that comes with age — the loss of the capacity to receive pleasure — is the type of the gradual wearing away of the present-age body: &#8220;though our outer self is wasting away, our inner self is being renewed day by day&#8221; (2 Cor 4:16). Barzillai&#8217;s honest assessment of his condition — no longer able to appreciate what the king offers — is the type of the believer&#8217;s honest acknowledgment that the full enjoyment of the kingdom awaits resurrection bodies that cannot wear out.</p>",
    "36": "<p>&#8220;Your servant will cross the Jordan with the king for a short way. Why should the king give me such a great reward?&#8221; Barzillai&#8217;s modesty — accompanying the king a short distance and considering that sufficient — is the type of the faithful servant who does not overestimate his own contribution. The parable of the unprofitable servant (Luke 17:10: &#8220;we have only done what was our duty&#8221;) captures the same posture. The anointed&#8217;s honor of such servants goes far beyond their self-assessment — &#8220;well done, good and faithful servant; you have been faithful over a little, I will set you over much&#8221; (Matt 25:21).</p>",
    "37": "<p>&#8220;Let your servant return to my own city, that I may die by the tombs of my father and mother.&#8221; Barzillai&#8217;s request to die at home — near the graves of his parents, in the city of his inheritance — is the earthly type of the resurrection hope that transcends it. Hebrews 11:16: the patriarchs who died in faith were &#8220;desiring a better country, that is, a heavenly one.&#8221; Barzillai desires the earthly inheritance; the resurrection hope offers the heavenly city of which the ancestral tomb is only a shadow. But his faithfulness in desiring to be received back to his inheritance is itself honored by the covenant.</p>",
    "38": "<p>&#8220;Chimham will cross with me, and I will do for him whatever you desire.&#8221; Barzillai sends his son in his place — the faithful old servant committing his son to the king&#8217;s care. The generational handing-on of covenant relationship — &#8220;as I have served the king, let the king receive my son&#8221; — is the type of the covenant that runs through generations. &#8220;The promise is for you and for your children and for all who are far off&#8221; (Acts 2:39) — Barzillai&#8217;s covenant service generates a covenant inheritance for Chimham. The anointed king accepts the son of the faithful servant as his own.</p>",
    "39": "<p>David kissed Barzillai and blessed him — the covenant kiss and blessing at parting. The kiss of the anointed is the covenant seal; the blessing pronounced over the faithful servant is the spoken covenant favor. Christ&#8217;s farewell blessing at the Ascension — &#8220;lifting up his hands he blessed them&#8221; (Luke 24:50) — is the supreme instance of the anointed&#8217;s parting blessing over those who have served him. The blessing that Barzillai carries back to his own land is the type of the blessing that the church carries into the world after the anointed&#8217;s departure.</p>",
    "40": "<p>The king went to Gilgal with Chimham — the covenant renewal site. Gilgal, where Israel was circumcised after crossing the Jordan (Josh 5), where the kingdom was renewed under Samuel (1 Sam 11:15), is the recurring site of covenant fresh starts. The king crossing the Jordan and arriving at Gilgal with a new generation of covenant servants — Chimham replacing the generation that served him through the exile — is the type of the church&#8217;s ongoing renewal: each generation receives the covenant afresh at the font (the circumcision-type) and the table (the Gilgal-feast type).</p>",
    "41": "<p>The men of Israel come to the king: &#8220;Why did our brothers, the men of Judah, steal you away?&#8221; The inter-tribal dispute over who gets to welcome the returning king is the type of the divisions within the church over who has priority in Christ&#8217;s household. The Corinthian &#8220;I am of Paul, I am of Apollos&#8221; divisions (1 Cor 1:12) are the NT instance of the Judah-Israel dispute at the Jordan. The anointed belongs to no faction; the dispute over his loyalty is itself a failure to understand the nature of his kingship. &#8220;Was Paul crucified for you?&#8221; (1 Cor 1:13) — was it Judah&#8217;s king only?</p>",
    "42": "<p>Judah&#8217;s answer: &#8220;Because the king is our kinsman. Why are you angry about this?&#8221; The appeal to kinship as the basis for priority in welcoming the king reflects the pattern of Jewish priority in the gospel. Paul acknowledges this: &#8220;to the Jew first and also to the Greek&#8221; (Rom 1:16) — but this priority does not mean exclusivity. The Judah-kinship claim is valid but must not become an exclusionary claim. Christ&#8217;s own proclamation &#8220;I was sent only to the lost sheep of Israel&#8221; (Matt 15:24) is a Judah-priority statement that is quickly transcended by the Gentile woman&#8217;s faith (Matt 15:28).</p>",
    "43": "<p>&#8220;We have ten shares in the king, and we have more claim on David than you!&#8221; — the Israel-tribes disputing precedence with Judah over the anointed. The unresolved dispute at the end of ch19 sets up the Sheba rebellion of ch20 — the tribal division that follows immediately when the welcome of the returning king becomes a competition. The church&#8217;s divisive competitions over priority (who was first, who has more, whose tradition is more legitimate) are the Judah-Israel dispute replayed. &#8220;Let us not become conceited, provoking one another, envying one another&#8221; (Gal 5:26) — the anointed&#8217;s return should produce unity, not a fight over credit.</p>"
  },
  "20": {
    "1": "<p>Sheba son of Bichri — a worthless man, a Benjaminite — blows the shofar: &#8220;We have no share in David!&#8221; Immediately after Absalom&#8217;s death a new rebel arises: the pattern of repeated uprising against the true anointed before the final settlement. Rev 20:7-9: after the millennium, Satan is released and goes out to deceive the nations, gathering them for battle against the beloved city — the Sheba pattern is the type of the final eschatological rebellion that immediately precedes the permanent kingdom. Every apparent settlement in the anointed&#8217;s history is followed by another uprising until the final victory.</p>",
    "2": "<p>All the men of Israel left David and followed Sheba — only the men of Judah stayed with the king. The moment of maximum defection: the entire northern alliance abandons the anointed for the voice of a worthless man. The type of the eschatological defection: &#8220;many will fall away and betray one another and hate one another&#8221; (Matt 24:10); &#8220;that day will not come, unless the rebellion comes first&#8221; (2 Thess 2:3). The church&#8217;s history will include mass defection from the anointed before the final establishment of his kingdom. The remnant that stays with the king — Judah here, the faithful church in the end-times — is the constant through the defections.</p>",
    "3": "<p>David&#8217;s ten concubines shut away &#8220;in living widowhood&#8221; — neither dead nor free to remarry. The tragedy of those left in the liminal state — alive but unable to function fully in their covenant role — is the type of the broken covenant relationships that sin creates. The concubines pay the price for Absalom&#8217;s rebellion; they are collateral damage of the usurper&#8217;s actions. Christ&#8217;s passion bears the cost that others should pay — &#8220;he was wounded for our transgressions; he was crushed for our iniquities&#8221; (Isa 53:5). The ten women in perpetual half-life are the type of those whose lives are suspended by sin&#8217;s consequences, awaiting the resurrection that will fully restore what was broken.</p>",
    "4": "<p>David orders Amasa to muster Judah within three days. The newly appointed commander given a specific assignment within a specific time is the type of every commission the anointed gives to his servants: &#8220;go into all the world and proclaim the gospel to the whole creation&#8221; (Mark 16:15) with the implicit urgency. Amasa&#8217;s failure to deliver on time (v. 5) — whatever the reason — will cost him his life. The anointed&#8217;s commissions have real deadlines; faithfulness requires not only eventual compliance but timely obedience.</p>",
    "5": "<p>Amasa took longer than the appointed time. The delay of the appointed commander — when the situation required immediate action — is the type of the danger of procrastination in the anointed&#8217;s service. The parable of the ten virgins (Matt 25:1-13) centers on precisely this: delay, the failure to be ready at the appointed moment, results in exclusion. Not every delay is fatal; but delay in answering the anointed&#8217;s commission can have irreversible consequences — as Amasa&#8217;s delay has for him in the narrative that follows.</p>",
    "6": "<p>&#8220;Sheba will do us more harm than Absalom did.&#8221; The assessment that the secondary rebellion is more dangerous than the primary is the type of Paul&#8217;s warning about the dangers of the second apostasy: &#8220;it is impossible, in the case of those who have once been enlightened... and then have fallen away, to restore them again to repentance&#8221; (Heb 6:4-6). The second rebellion against the anointed — coming after the first has been apparently defeated — is characterized by a deeper hardening and a more dangerous destabilization. The quick action required against Sheba is the type of the urgency of addressing false teaching before it takes root in the church.</p>",
    "7": "<p>Joab&#8217;s men, the Cherethites and Pelethites, all the warriors marching out from Jerusalem — the full military force of the anointed deployed against the new rebellion. The comprehensive deployment of the anointed&#8217;s forces against the eschatological rebellion mirrors Rev 19:11-16: the rider on the white horse coming with the armies of heaven to defeat the final rebellion. The anointed&#8217;s forces pursuing the rebel-band through the land is the type of Christ&#8217;s pursuit of every pocket of resistance to his kingdom until all enemies are made his footstool (1 Cor 15:25).</p>",
    "8": "<p>At the great stone in Gibeon, Joab — with his sword already drawn under his garment — meets Amasa. The treachery disguised as greeting is the type of false brotherhood within the anointed&#8217;s community. Paul warns: &#8220;false brothers secretly brought in&#8221; (Gal 2:4); &#8220;savage wolves will come in among you&#8221; (Acts 20:29). The sword hidden under military clothing — the weapon concealed until the moment of the embrace — is the type of the wolf in sheep&#8217;s clothing (Matt 7:15). Gibeon, the site of the previous champions-combat, becomes the site of another treacherous killing.</p>",
    "9": "<p>Joab&#8217;s greeting — &#8220;Are you well, my brother?&#8221; — while seizing Amasa by the beard to kiss him, then stabbing him. The greeting that is also the ambush is the type of Judas&#8217;s kiss: &#8220;the one I will kiss is the man; arrest him&#8221; (Matt 26:48). The covenant-greeting (kiss, address as &#8220;brother&#8221;) used as the signal for treachery is the ultimate violation of covenant trust. Christ calls Judas &#8220;friend&#8221; even as Judas betrays him (Matt 26:50: &#8220;Friend, do what you came to do&#8221;) — the anointed receives the traitor&#8217;s kiss with covenant dignity even knowing its meaning.</p>",
    "10": "<p>Amasa did not notice the sword in Joab&#8217;s hand — he did not expect treachery from his brother. The vulnerability of trust — the way genuine openness creates the conditions for betrayal — is the pattern of Christ&#8217;s own passion: &#8220;he came to his own, and his own people did not receive him&#8221; (John 1:11). The anointed&#8217;s openness to those who come to him — his refusal to protect himself by suspicion — creates the space in which betrayal operates. Amasa&#8217;s death by the sword he did not see coming is the type of every death by trusted treachery; Christ&#8217;s death is the supreme instance.</p>",
    "11": "<p>Joab&#8217;s man standing over Amasa&#8217;s body, demanding: &#8220;Whoever is for Joab and whoever is for David — follow Joab!&#8221; The forced loyalty choice — follow the treacherous general or be identified as the enemy — is the type of the binary loyalty demand that coercive powers use to secure compliance. Christ&#8217;s own statement &#8220;whoever is not with me is against me&#8221; (Matt 12:30) operates differently: it is not coercive but ontological — the kingdom&#8217;s claim is absolute not because it threatens violence but because there is no neutral ground before the anointed. Joab&#8217;s binary is false (loyalty to him is not loyalty to David); Christ&#8217;s binary is true (loyalty to him is loyalty to the Father).</p>",
    "12": "<p>Amasa&#8217;s body in the road, wallowing in blood — the man dragged aside so the army will keep moving. The tragedy of the faithful servant killed by the treacherous colleague, whose death becomes a logistical problem to be managed, is the type of every martyr whose death is disposed of so the anointed&#8217;s cause can continue. Acts 8:2: &#8220;devout men buried Stephen and made great lamentation over him&#8221; — the faithful who die in the anointed&#8217;s service are mourned, even as the mission continues. Amasa&#8217;s body moved from the road is not dishonor but necessity; the mission cannot stop for every martyr&#8217;s death.</p>",
    "13": "<p>Once Amasa&#8217;s body was moved from the road, every man went on after Joab to pursue Sheba. The mission resuming after the tragedy — the army moving forward despite the loss — is the type of the church&#8217;s continued mission through persecution and martyrdom. &#8220;Those who were scattered went about preaching the word&#8221; (Acts 8:4) after Stephen&#8217;s death. The road cleared of the obstacle, the mission continues. The anointed&#8217;s cause does not end with any servant&#8217;s death; the pursuit of the rebel continues until he is overtaken.</p>",
    "14": "<p>Sheba passes through all the tribes to Abel Beth-maacah; all the Bichrites follow him. The rebel leader gathering a following in the northernmost city — the furthest from the anointed&#8217;s capital — is the type of the eschatological gathering of the nations for the final battle: &#8220;and they marched up over the broad plain of the earth and surrounded the camp of the saints and the beloved city&#8221; (Rev 20:9). The rebel&#8217;s retreat to the margins — the city farthest from Jerusalem — and the gathering of his last followers there is the type of the enemy&#8217;s final stand before the anointed&#8217;s complete victory.</p>",
    "15": "<p>Joab&#8217;s forces lay siege to Abel Beth-maacah — a siege ramp built against the wall. The military technology of siege against the rebel&#8217;s last stronghold is the type of the eschatological confrontation between the anointed&#8217;s kingdom and the last pocket of resistance. &#8220;The gates of hell shall not prevail against it&#8221; (Matt 16:18) — but the image is of the church pressing against the gates of the enemy, not the enemy pressing against the church. The anointed&#8217;s forces laying siege to the rebel&#8217;s stronghold is the aggressive posture of the advancing kingdom against its last opposition.</p>",
    "16": "<p>A wise woman in the city calls out — &#8220;Listen! Listen! Tell Joab to come near.&#8221; The wise woman who intervenes between the besieging army and her city is one of the remarkable female wisdom-figures in Samuel (cf. the wise woman of Tekoa, 2 Sam 14:2). Her wisdom is the instrument of salvation for the city — &#8220;wisdom has built her house&#8221; (Prov 9:1); &#8220;Christ the power of God and the wisdom of God&#8221; (1 Cor 1:24). The woman whose voice stops a siege is the type of wisdom as the preserving principle — the word that speaks peace where violence threatens.</p>",
    "17": "<p>&#8220;Hear the words of your servant.&#8221; The woman&#8217;s self-designation as &#8220;servant&#8221; (<em>ʾāmāh</em>) and her insistence on being heard is the type of the humble wisdom that speaks truth to power. The wisdom of God communicated through the lowly — &#8220;God chose what is foolish in the world to shame the wise; God chose what is weak in the world to shame the strong&#8221; (1 Cor 1:27) — is the principle the wise woman embodies. Christ speaks from the cross as a condemned criminal; his wisdom is the wisdom that stops the siege of sin and death.</p>",
    "18": "<p>&#8220;In the old days they used to say, &#8216;Get your answer at Abel&#8217; — and that is how they settled things.&#8221; The appeal to the city&#8217;s historic role as a center of wisdom and mediation is the appeal to covenant tradition. The woman is saying: this city has a covenant function — it is a place where disputes are settled by wisdom, not destroyed by siege. Christ&#8217;s appeal to the Torah and Prophets — &#8220;have you not read?&#8221;, &#8220;it is written&#8221; — is the appeal to the covenant tradition as the standard for resolving disputes. The anointed&#8217;s wisdom draws on the deep covenant tradition to resolve what force cannot.</p>",
    "19": "<p>&#8220;I am of the peaceable and faithful in Israel. You are trying to destroy a city that is a mother in Israel.&#8221; The city described as a &#8220;mother in Israel&#8221; — a covenant center that nurtures and sustains the community — is the type of Jerusalem as the mother-city (Gal 4:26: &#8220;the Jerusalem above is free, and she is our mother&#8221;). The destruction of what is a covenant-nurturing center is the destruction of something sacred; wisdom resists it. The church as the &#8220;mother in Israel&#8221; — the nurturing, peaceable, faithful community — is what the enemy&#8217;s siege always targets.</p>",
    "20": "<p>Joab: &#8220;Far be it from me that I should swallow up or destroy!&#8221; Joab&#8217;s stated commitment to not destroying the innocent city is itself the type of the anointed&#8217;s restraint: &#8220;God did not send his Son into the world to condemn the world, but that the world might be saved through him&#8221; (John 3:17). The forces of the anointed are deployed against the rebel, not against the city or the innocent. The distinction between the rebel (Sheba) and the city that harbors him is the type of the gospel&#8217;s distinction between the sinner (who is sought for redemption) and sin (which must be destroyed).</p>",
    "21": "<p>The solution: hand over one man, Sheba son of Bichri, and the city will be spared. The principle that one man&#8217;s death saves the city is the substitutionary logic that the cross fulfills in the ultimate register. Caiaphas&#8217;s unconscious prophecy: &#8220;it is better for you that one man should die for the people, not that the whole nation should perish&#8221; (John 11:50) — the high priest speaks more truth than he knows. The one rebel handed over so the city might be saved is the type of Christ offered up so the whole city — the whole covenant community — might be spared.</p>",
    "22": "<p>The wise woman persuaded the people; they cut off Sheba&#8217;s head and threw it to Joab. The city is saved; Joab blows the trumpet and withdraws. The wisdom-speaker who persuaded the community to surrender the rebel — &#8220;she went to all the people in her wisdom&#8221; — is the type of the Spirit&#8217;s convicting work: &#8220;he will convict the world concerning sin and righteousness and judgment&#8221; (John 16:8). The wise woman&#8217;s persuasion of the whole city to act for their salvation is the type of the gospel proclamation that brings the community to surrender what must be surrendered so that all might live.</p>",
    "23": "<p>Joab over all Israel&#8217;s army; Benaiah over the Cherethites and Pelethites — the administrative list of the kingdom&#8217;s offices after the rebellion&#8217;s suppression. The ordering of the kingdom after the victory is the type of the church&#8217;s ordering under Christ&#8217;s apostolic gifts: &#8220;he gave the apostles, the prophets, the evangelists, the shepherds and teachers, to equip the saints for the work of ministry&#8221; (Eph 4:11-12). The military and administrative structure of the established kingdom is the earthly type of Christ&#8217;s ordering of his church for its mission in the world.</p>",
    "24": "<p>Adoram over forced labor; Jehoshaphat the recorder. The administrative roles of the kingdom — labor, record-keeping — reflect the ordering of the community for sustained operation. The church requires both the labor of service (deacons, workers) and the recording of the word (scribes, teachers). Paul&#8217;s instruction about the ordering of the household of God (1 Tim 3) and the variety of gifts (1 Cor 12) reflects the same principle: every function in the anointed&#8217;s kingdom has its appointed role and its appointed overseer.</p>",
    "25": "<p>Sheva the secretary; Zadok and Abiathar the priests. The dual priesthood — two priests serving together — is the type of the intercession that is both earthly (the church&#8217;s prayers) and heavenly (Christ&#8217;s high priestly intercession). &#8220;We have a great high priest who has passed through the heavens, Jesus the Son of God&#8221; (Heb 4:14) — the single true priest who supersedes the dual earthly priesthood and makes permanent intercession. Zadok and Abiathar serve together in the kingdom&#8217;s administration; Christ alone serves in the heavenly sanctuary as the one mediator.</p>",
    "26": "<p>Ira the Jairite was David&#8217;s personal priest. The closing of the administrative list with a personal priest for the king is a type of the individual believer&#8217;s personal access to the anointed&#8217;s priestly intercession. Heb 7:25: Christ &#8220;always lives to make intercession&#8221; — not a general or institutional intercession only, but a personal intercession for those who draw near through him. The king&#8217;s personal priest who ministers specifically to the anointed is the type of the Spirit who intercedes for each believer &#8220;with groanings too deep for words&#8221; (Rom 8:26).</p>"
  },
  "21": {
    "1": "<p>Three years of famine; David seeks YHWH&#8217;s face; YHWH says it is for Saul&#8217;s violation of the Gibeonites. The famine traced to a covenantal violation from the previous generation is the type of the inherited consequences of sin. Paul&#8217;s argument in Rom 5:12: &#8220;sin came into the world through one man, and death through sin&#8221; — the whole human family inherits the consequences of Adam&#8217;s covenant violation. David seeking YHWH&#8217;s face to understand the source of the affliction is the type of the faithful who go to YHWH to diagnose the root of suffering rather than treating symptoms only.</p>",
    "2": "<p>The Gibeonites were not Israelites but a remnant of the Amorites — protected by the oath of Joshua (Josh 9). Israel had sworn to preserve them; Saul violated that oath. The binding force of a covenant oath — even sworn to non-Israelites, even binding on the next generation — is the type of the eternal covenant&#8217;s binding force. Christ&#8217;s new covenant is sealed with his own blood (Luke 22:20); its obligations bind all who enter it across every generation. The covenant oath sworn to the Gibeonites, binding on Israel long after Joshua&#8217;s death, is the type of the covenant oath that binds the church to Christ&#8217;s terms across all generations.</p>",
    "3": "<p>&#8220;What shall I do for you? How shall I make atonement (<em>ʾăkappēr</em>)?&#8221; David&#8217;s question about atonement for covenant violation is the OT&#8217;s central question about sin: how is covenant violation repaired? The answer in 21:3-9 — through substitutionary death — is the type of the gospel&#8217;s answer. Christ&#8217;s death is the ultimate <em>kipper</em> (atonement): &#8220;he is the propitiation for our sins&#8221; (1 John 2:2). The king asking &#8220;how shall I make atonement?&#8221; is every human being before the covenant God; Christ&#8217;s cross is the divine answer to the question David can only type.</p>",
    "4": "<p>The Gibeonites: &#8220;It is not a matter of silver or gold between us and Saul, and we have no right to put anyone in Israel to death.&#8221; The refusal of monetary compensation for blood-guilt — the declaration that some violations cannot be settled by financial payment — is the type of the gospel&#8217;s declaration about sin: &#8220;you were ransomed from the futile ways inherited from your forefathers, not with perishable things such as silver or gold&#8221; (1 Pet 1:18). The atonement for blood-guilt requires the appropriate payment; the Gibeonites&#8217; refusal of silver points toward the costly blood-price that alone can satisfy.</p>",
    "5": "<p>&#8220;The man who consumed us and who planned to destroy us.&#8221; The Gibeonite description of Saul&#8217;s genocidal intent is the type of the enemy&#8217;s program against the covenant people — and against humanity as a whole. John 10:10: &#8220;the thief comes only to steal and kill and destroy.&#8221; The one who planned to destroy the covenant-protected is the type of the enemy whose plan is annihilation. Christ comes as the answer to the destroying plan: &#8220;I came that they may have life and have it abundantly&#8221; — the contrast between the destroyer&#8217;s program and the anointed&#8217;s purpose.</p>",
    "6": "<p>&#8220;Let seven of his male descendants be handed over to us, to hang them before YHWH at Gibeah of Saul.&#8221; Seven sons as substitute for the covenant-violating king is the substitutionary principle: the sins of the fathers visited on the children (Exod 20:5). The seven men who die for Saul&#8217;s violation of the Gibeonite covenant are types of the substitutionary death that clears the blood-guilt. But the NT&#8217;s reversal is decisive: &#8220;the Son of Man came not to be served but to serve, and to give his life as a ransom for many&#8221; (Matt 20:28) — in Christ, the innocent dies in the place of the guilty, not the descendants for their ancestor.</p>",
    "7": "<p>The king spared Mephibosheth son of Jonathan because of the covenant oath between David and Jonathan. The covenant oath that shelters the one who would otherwise perish is the type of Christ&#8217;s covenant that shelters believers from the judgment that their guilt deserves. &#8220;There is therefore now no condemnation for those who are in Christ Jesus&#8221; (Rom 8:1) — those in covenant with the anointed are sheltered by the oath sworn between the anointed and the Father. Mephibosheth is not spared by his own merit but by the covenant oath that preceded his existence; believers are saved by the covenant made before the foundation of the world (Eph 1:4).</p>",
    "8": "<p>The king took the two sons of Rizpah and the five sons of Michal and handed them over to the Gibeonites. The seven men handed over — innocent descendants of the covenant violator — are the type of those who bear punishment for inherited sin. But the NT transformation is complete: Christ bears the punishment for Adam&#8217;s descendants — &#8220;as one trespass led to condemnation for all men, so one act of righteousness leads to justification and life for all men&#8221; (Rom 5:18). The seven bear the sin of one king; Christ bears the sin of all humanity. The substitution runs in the opposite direction: not the innocent many for the guilty one, but the innocent One for the guilty many.</p>",
    "9": "<p>The seven were hanged on the mountain before YHWH — all seven fell together in the first days of harvest. The execution before YHWH on the mountain — a public, covenant-sanctioned death that addresses the blood-guilt — is the type of the cross as a public execution before YHWH that addresses all humanity&#8217;s blood-guilt. Deut 21:23: &#8220;cursed is everyone who is hanged on a tree&#8221; — Paul quotes this in Gal 3:13: &#8220;Christ redeemed us from the curse of the law by becoming a curse for us — for it is written, &#8216;cursed is everyone who is hanged on a tree.&#8217;&#8221; The seven hanged before YHWH on the mountain are types of the one who hangs on the tree to bear the covenant curse.</p>",
    "10": "<p>Rizpah spread sackcloth on a rock and kept watch from the beginning of harvest until the rains fell, guarding the bodies from birds and beasts by day and night. The devoted vigil of the woman who would not let the executed bodies be dishonored is one of the most powerful images in Samuel. The women at the cross who &#8220;watched from afar&#8221; (Matt 27:55-56; Mark 15:40; Luke 23:49) and the women at the tomb who came to anoint Christ&#8217;s body (Luke 24:1) are the NT instances of Rizpah&#8217;s faithfulness. The covenant devotion that refuses to abandon the crucified body — staying through the long watches — is the type of the women who honor the dead anointed.</p>",
    "11": "<p>David was told what Rizpah had done. The faithful woman&#8217;s vigil reaches the king&#8217;s ears — her covenant devotion generates a royal response. The faithfulness of those who honor the anointed&#8217;s fallen servants does not go unnoticed by the king. Matt 26:13: the woman who anointed Jesus — &#8220;wherever this gospel is proclaimed in the whole world, what she has done will also be told in memory of her.&#8221; The anointed king hears of every act of covenant devotion performed in the shadow of his absence and will honor it at the resurrection.</p>",
    "12": "<p>David retrieves the bones of Saul and Jonathan from Jabesh-gilead — the men who had honored the fallen king at great risk (1 Sam 31:11-13) are now honored in return by David&#8217;s action. The gathering of the honored dead is the type of the resurrection: &#8220;the Lord himself will descend from heaven with a cry of command, with the voice of an archangel, and with the sound of the trumpet of God. And the dead in Christ will rise first&#8221; (1 Thess 4:16). David gathers the scattered bones of the fallen anointed; Christ will gather the scattered bones of all his own at the resurrection.</p>",
    "13": "<p>The bones of Saul and Jonathan brought together with the bones of the seven executed sons. The gathering of all the honored dead — bringing scattered remains together — is the type of the general resurrection in which all who belong to the anointed will be gathered: &#8220;they will gather his elect from the four winds, from one end of heaven to the other&#8221; (Matt 24:31). No bone is left behind; no servant of the covenant is forgotten. &#8220;Precious in the sight of YHWH is the death of his faithful ones&#8221; (Ps 116:15) — the king who gathers the bones honors this truth.</p>",
    "14": "<p>They buried the bones in Zela of Benjamin, in the tomb of Kish, Saul&#8217;s father. &#8220;After this God was moved by prayer for the land.&#8221; The proper burial of the covenant dead — their return to the ancestral inheritance — and the divine response of relenting from the judgment is the type of the resurrection&#8217;s resolution of all outstanding accounts. The blood-guilt for the Gibeonites resolved; the bones of the fallen honored; YHWH&#8217;s face turned toward the land again — the full cycle of judgment, atonement, burial, and restoration is the type of the redemptive sequence culminating in the new creation.</p>",
    "15": "<p>War again between the Philistines and Israel — David went down and fought. The recurring warfare that follows every apparent settlement is the pattern of the anointed&#8217;s ongoing campaign against the enemies of the kingdom. &#8220;He must reign until he has put all his enemies under his feet&#8221; (1 Cor 15:25) — the last enemy to be destroyed is death (v. 26), but before that last enemy, there are many battles. The anointed who keeps returning to battle is the type of Christ&#8217;s unrelenting advance against the powers of the present age.</p>",
    "16": "<p>Ishbi-benob, a descendant of the giants, nearly killed David — his bronze spear weighed three hundred shekels, and he was girded with a new sword. The giant who nearly kills the anointed king is the type of the mortal threat that the powers of the old order pose to the anointed. Christ&#8217;s temptation in the wilderness (Matt 4:1-11), Gethsemane&#8217;s agony (Luke 22:44), and the cross are the supreme moments of the giant&#8217;s near-victory against the anointed. The power of the enemy is real; it nearly destroys; only the intervention of another can save.</p>",
    "17": "<p>Abishai rescued David and killed the Philistine. David&#8217;s men swore: &#8220;You shall not go out to battle with us anymore, lest you extinguish the lamp of Israel.&#8221; The title &#8220;lamp of Israel&#8221; (<em>nēr yiśrāʾēl</em>) for the anointed king is the most theologically freighted title in the passage. Christ as &#8220;the light of the world&#8221; (John 8:12), the &#8220;true light that gives light to everyone&#8221; (John 1:9), is the fulfillment of the lamp-of-Israel metaphor. The fear that the anointed might be extinguished — that the source of Israel&#8217;s light might go dark — is the fear that the cross appeared to realize. The resurrection is the lamp that cannot be extinguished.</p>",
    "18": "<p>Another battle at Gob; Sibbecai the Hushathite killed Saph, another descendant of the giants. David&#8217;s servants defeating the giants that David himself can no longer face in battle is the type of the church continuing Christ&#8217;s victory against his enemies. Col 1:24: &#8220;I rejoice in my sufferings for your sake, and in my flesh I am filling up what is lacking in Christ&#8217;s afflictions for the sake of his body, that is, the church&#8221; — the church participates in completing the campaign that the anointed initiated. The servants fight the battles the anointed has commissioned them to fight.</p>",
    "19": "<p>Another battle at Gob; Elhanan killed Goliath the Gittite. The recurrence of Goliath-type enemies — giant after giant requiring defeat — is the type of the principalities and powers that Christ&#8217;s church confronts in every generation: &#8220;we wrestle not against flesh and blood, but against the rulers, against the authorities, against the cosmic powers over this present darkness&#8221; (Eph 6:12). Each generation of the anointed&#8217;s servants faces its own Goliath; each must be defeated by those the anointed has equipped and commissioned.</p>",
    "20": "<p>A man of great stature at Gath, with six fingers on each hand and six toes on each foot — a champion taunting Israel. The enemy who taunts the covenant people of the anointed is the type of the accuser who challenges the church&#8217;s legitimacy and standing. Rev 12:10: &#8220;the accuser of our brothers has been thrown down, who accuses them day and night before our God.&#8221; The giant&#8217;s taunting (the same word used for Goliath&#8217;s challenge in 1 Sam 17) is the anti-anointed pattern: the enemy&#8217;s weapon is not only force but challenge and mockery of the covenant community&#8217;s claim to the anointed&#8217;s protection.</p>",
    "21": "<p>Jonathan son of Shimei, David&#8217;s brother, struck the giant down. The king&#8217;s own kinsman — a member of the royal family — killing the taunter is the type of Christ&#8217;s own work of silencing the accuser: &#8220;the accuser of our brothers has been thrown down&#8221; (Rev 12:10) by the one who conquered through his own blood. The taunter who challenges the anointed&#8217;s people is answered not by the whole army but by the one who bears the anointed&#8217;s name and shares his family.</p>",
    "22": "<p>&#8220;These four were descendants of the giants in Gath, and they fell by the hand of David and his servants.&#8221; The concluding formula — four giants defeated by the anointed and his servants together — is the summary statement of the church&#8217;s mission: the battle against the enemies of the kingdom is a joint work of Christ and those who serve him. &#8220;We are more than conquerors through him who loved us&#8221; (Rom 8:37) — not apart from Christ, not by Christ alone without the participation of his servants, but together: &#8220;by the hand of David and his servants.&#8221; The anointed and his people share the victory over the giants of the old order.</p>"
  }
}

def main():
    c = load_comm('christ', '2samuel')
    merge_comm(c, CHRIST)
    save_comm('christ', '2samuel', c)
    total = sum(len(v) for v in CHRIST.values())
    print(f'2samuel mkt-christ: wrote {total} verses across ch 19-21')

if __name__ == '__main__':
    main()
